package ccxt

type Weex struct {
	*WeexCore
	Core          *WeexCore
	exchangeTyped *ExchangeTyped
}

func NewWeex(userConfig map[string]interface{}) *Weex {
	p := NewWeexCore()
	p.Init(userConfig)
	return &Weex{
		WeexCore:      p,
		Core:          p,
		exchangeTyped: NewExchangeTyped(&p.Exchange),
	}
}
func NewWeexFromCore(core *WeexCore) *Weex {
	return &Weex{
		WeexCore:      core,
		Core:          core,
		exchangeTyped: NewExchangeTyped(&core.Exchange),
	}
}

